// Generated by forge proof from worktree-aware-audit.md, worktree-aware-proof.md, worktree-aware-watch.md
import { describe, test, expect, beforeEach } from 'bun:test';
import {
  getTestDb,
  insertWorktree,
  getWorktree,
  transitionWorktreeStatus,
  querySessionsByWorktree,
  insertSession,
  insertTask,
} from './db.js';
import type { Database } from 'bun:sqlite';
import type { WorktreeStatus } from './db.js';

let db: Database;

beforeEach(() => {
  db = getTestDb();
});

function insertTestWorktree(overrides: Partial<Parameters<typeof insertWorktree>[1]> = {}): string {
  const id = `wt-aware-${Date.now()}-${Math.random().toString(16).substring(2, 6)}`;
  insertWorktree(db, {
    id,
    spec_path: 'specs/feature.md',
    branch: 'forge/feature',
    worktree_path: '/tmp/project-feature',
    status: 'created',
    ...overrides,
  });
  return id;
}

// ── Worktree-aware audit ─────────────────────────────────────

describe('worktree-aware audit lifecycle', () => {
  test('worktree transitions: complete -> auditing -> audited', () => {
    const id = insertTestWorktree();
    transitionWorktreeStatus(db, id, 'running');
    transitionWorktreeStatus(db, id, 'complete');
    transitionWorktreeStatus(db, id, 'auditing');

    expect(getWorktree(db, id)!.status).toBe('auditing');

    transitionWorktreeStatus(db, id, 'audited');
    expect(getWorktree(db, id)!.status).toBe('audited');
  });

  test('audit failure transitions: auditing -> failed', () => {
    const id = insertTestWorktree();
    transitionWorktreeStatus(db, id, 'running');
    transitionWorktreeStatus(db, id, 'complete');
    transitionWorktreeStatus(db, id, 'auditing');
    transitionWorktreeStatus(db, id, 'failed', 'Audit failed: 5 gaps found');

    const wt = getWorktree(db, id);
    expect(wt!.status).toBe('failed');
    expect(wt!.error).toBe('Audit failed: 5 gaps found');
  });

  test('worktree resolves path from registry', () => {
    const wtPath = '/home/dev/project-auth';
    const id = insertTestWorktree({ worktree_path: wtPath });

    const wt = getWorktree(db, id);
    expect(wt!.worktree_path).toBe(wtPath);
    // In real usage: audit reads code from wt.worktree_path
  });

  test('audit results persist via persistDir (worktree_path != cwd)', () => {
    // The audit uses worktree_path for reading code but persists to original repo
    const id = insertTestWorktree({
      worktree_path: '/dev/project-auth-worktree',
    });

    const wt = getWorktree(db, id);
    // persistDir would be the original repo, not the worktree
    expect(wt!.worktree_path).toBe('/dev/project-auth-worktree');
  });
});

// ── Worktree-aware proof ─────────────────────────────────────

describe('worktree-aware proof lifecycle', () => {
  test('worktree transitions: audited -> proofing -> proofed', () => {
    const id = insertTestWorktree();
    transitionWorktreeStatus(db, id, 'running');
    transitionWorktreeStatus(db, id, 'complete');
    transitionWorktreeStatus(db, id, 'auditing');
    transitionWorktreeStatus(db, id, 'audited');
    transitionWorktreeStatus(db, id, 'proofing');

    expect(getWorktree(db, id)!.status).toBe('proofing');

    transitionWorktreeStatus(db, id, 'proofed');
    expect(getWorktree(db, id)!.status).toBe('proofed');
  });

  test('proof can skip audit: complete -> proofing -> proofed', () => {
    const id = insertTestWorktree();
    transitionWorktreeStatus(db, id, 'running');
    transitionWorktreeStatus(db, id, 'complete');
    transitionWorktreeStatus(db, id, 'proofing');
    transitionWorktreeStatus(db, id, 'proofed');

    expect(getWorktree(db, id)!.status).toBe('proofed');
  });

  test('proof failure: proofing -> failed', () => {
    const id = insertTestWorktree();
    transitionWorktreeStatus(db, id, 'running');
    transitionWorktreeStatus(db, id, 'complete');
    transitionWorktreeStatus(db, id, 'proofing');
    transitionWorktreeStatus(db, id, 'failed', 'Test generation failed');

    expect(getWorktree(db, id)!.status).toBe('failed');
    expect(getWorktree(db, id)!.error).toBe('Test generation failed');
  });

  test('worktree branch info available for diff scoping', () => {
    const id = insertTestWorktree({ branch: 'forge/ENG-123/auth-login' });

    const wt = getWorktree(db, id);
    // In real usage: proof uses git diff main...{branch} for scoping
    expect(wt!.branch).toBe('forge/ENG-123/auth-login');
  });
});

// ── Worktree-scoped watch ────────────────────────────────────

describe('worktree-scoped watch', () => {
  test('finds sessions by worktree direct link', () => {
    const id = insertTestWorktree({ session_id: 'sess-watch-1' });

    insertSession(db, {
      id: 'sess-watch-1',
      startedAt: '2026-01-01T00:00:00Z',
      commandType: 'run',
    });

    const sessions = querySessionsByWorktree(db, id);
    expect(sessions).toHaveLength(1);
    expect(sessions[0].id).toBe('sess-watch-1');
  });

  test('finds sessions by task cwd matching worktree path', () => {
    const id = insertTestWorktree({
      worktree_path: '/dev/project-watch-wt',
    });

    insertSession(db, {
      id: 'sess-watch-task',
      startedAt: '2026-01-01T00:00:00Z',
      commandType: 'run',
    });
    insertTask(db, {
      id: 'task-watch-1',
      command: 'run',
      status: 'completed',
      cwd: '/dev/project-watch-wt',
      sessionId: 'sess-watch-task',
    });

    const sessions = querySessionsByWorktree(db, id);
    expect(sessions).toHaveLength(1);
    expect(sessions[0].id).toBe('sess-watch-task');
  });

  test('auto-follow stays within worktree sessions (ordered ASC)', () => {
    const id = insertTestWorktree({
      worktree_path: '/dev/project-follow',
      session_id: 'sess-follow-2',
    });

    insertSession(db, { id: 'sess-follow-1', startedAt: '2026-01-01T00:00:00Z' });
    insertSession(db, { id: 'sess-follow-2', startedAt: '2026-01-01T01:00:00Z' });
    insertSession(db, { id: 'sess-other', startedAt: '2026-01-01T02:00:00Z' });

    insertTask(db, {
      id: 'task-follow-1',
      command: 'run',
      status: 'completed',
      cwd: '/dev/project-follow',
      sessionId: 'sess-follow-1',
    });

    const sessions = querySessionsByWorktree(db, id);
    // Should only contain sessions in this worktree, ordered ASC
    expect(sessions).toHaveLength(2);
    expect(sessions[0].id).toBe('sess-follow-1');
    expect(sessions[1].id).toBe('sess-follow-2');
    // sess-other should NOT be included
    expect(sessions.find(s => s.id === 'sess-other')).toBeUndefined();
  });

  test('returns empty array for worktree with no sessions', () => {
    const id = insertTestWorktree();
    expect(querySessionsByWorktree(db, id)).toEqual([]);
  });

  test('deduplicates sessions found via both paths', () => {
    const id = insertTestWorktree({
      worktree_path: '/dev/dedup-watch',
      session_id: 'sess-dedup-w',
    });

    insertSession(db, { id: 'sess-dedup-w', startedAt: '2026-01-01T00:00:00Z' });
    insertTask(db, {
      id: 'task-dedup-w',
      command: 'run',
      status: 'completed',
      cwd: '/dev/dedup-watch',
      sessionId: 'sess-dedup-w',
    });

    const sessions = querySessionsByWorktree(db, id);
    expect(sessions).toHaveLength(1);
  });
});
